import React, {useState} from 'react';
import {Button, Modal} from 'react-bootstrap';


//add the instructions after the thing damn resets! This is absurd.

const MealModal = ({id, title, image, summary, name, content}) => {
  
  const [show, setShow] = useState(false);

  const handleClose = () => setShow(false);
  const handleShow = () => setShow(true);


    return (
      <>
      <Button variant="primary" onClick={handleShow}>
        See More
      </Button>
      <Modal show={show} onHide={handleClose}>
        <Modal.Header closeButton>
          <Modal.Title>{title}{name}</Modal.Title>
        </Modal.Header>
        <Modal.Body dangerouslySetInnerHTML={{__html: summary}}></Modal.Body>
        <Modal.Body dangerouslySetInnerHTML={{__html: content}}>{content}</Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={handleClose}>
            Close
          </Button>
          <Button variant="primary" onClick={handleClose}>
            Save Changes
          </Button>
        </Modal.Footer>
      </Modal>
    </>
      );
}

export default MealModal;
